async function loadPolyfills() {
  if (!("IntersectionObserver" in window)) {
    await import("intersection-observer");
  }
  if (!("ResizeObserver" in window)) {
    await import("@juggle/resize-observer");
  }
  if (!("fetch" in window)) {
    await import("whatwg-fetch");
  }
}

